const fmt = n => "$" + n.toLocaleString("es-CL");

function Stars({ n = 5 }) {
  return <span style={{ color:"#FFD700", letterSpacing:2 }}>{"★★★★★".slice(0, n)}</span>;
}

function Slider({ before, after }) {
  const [pos, setPos] = useState(50);
  const ref = useRef(null);
  const drag = useRef(false);
  const update = cx => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    setPos(Math.max(4, Math.min(96, (cx - r.left) / r.width * 100)));
  };
  return (
    <div ref={ref}
      style={{ position:"relative", aspectRatio:"3/4", borderRadius:16, overflow:"hidden", cursor:"ew-resize", userSelect:"none", background:C.bg2 }}
      onMouseDown={() => { drag.current = true; }}
      onMouseUp={() => { drag.current = false; }}
      onMouseLeave={() => { drag.current = false; }}
      onMouseMove={e => { if (drag.current) update(e.clientX); }}
      onTouchMove={e => update(e.touches[0].clientX)}>
      <img src={after}  alt="despues" style={{ position:"absolute", inset:0, width:"100%", height:"100%", objectFit:"cover" }} />
      <div style={{ position:"absolute", inset:0, width:`${pos}%`, overflow:"hidden" }}>
        <img src={before} alt="antes" style={{ width:`${10000/pos}%`, height:"100%", objectFit:"cover", objectPosition:"left" }} />
      </div>
      <div style={{ position:"absolute", top:0, bottom:0, left:`${pos}%`, transform:"translateX(-50%)", width:2, background:C.teal, boxShadow:`0 0 16px ${C.teal}` }} />
      <div style={{ position:"absolute", top:"50%", left:`${pos}%`, transform:"translate(-50%,-50%)", width:40, height:40, borderRadius:"50%", background:C.teal, display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, color:"#000", fontWeight:900, pointerEvents:"none", boxShadow:`0 0 24px ${C.teal}80` }}>⟺</div>
      <div style={{ position:"absolute", bottom:12, left:12, background:"#00000085", borderRadius:6, padding:"4px 10px", fontSize:11, fontWeight:700, letterSpacing:2, color:C.white }}>ANTES</div>
      <div style={{ position:"absolute", bottom:12, right:12, background:`${C.teal}CC`, borderRadius:6, padding:"4px 10px", fontSize:11, fontWeight:700, letterSpacing:2, color:"#000" }}>DESPUÉS</div>
    </div>
  );
}

